import org.springframework.data.domain.Sort;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ResponseStatusException;

import project.italy.backend.models.Categoria;
import project.italy.backend.models.ProdottoTipico;
import project.italy.backend.models.Regione;
import project.italy.backend.repository.ProdottoTipicoRepository;
import project.italy.backend.repository.RegioneRepository;
import project.italy.backend.repository.CategoriaRepository;

import java.util.List;

@RestController
@RequestMapping("/api/prodotti")
public class ProdottoTipicoController {

    private final ProdottoTipicoRepository prodottoTipicoRepository;
    private final RegioneRepository regioneRepository;
    private final CategoriaRepository categoriaRepository;

    // Dependency Injection dei repository necessari
    public ProdottoTipicoController(ProdottoTipicoRepository prodottoTipicoRepository,
                                    RegioneRepository regioneRepository,
                                    CategoriaRepository categoriaRepository) {
        this.prodottoTipicoRepository = prodottoTipicoRepository;
        this.regioneRepository = regioneRepository;
        this.categoriaRepository = categoriaRepository;
    }

    // Endpoint: /api/prodotti/regione/toscana?categoria=formaggi&orderBy=nome&direction=asc
    @GetMapping("/regione/{regioneSlug}")
    public ResponseEntity<List<ProdottoTipico>> getProdottiPerRegione(
            @PathVariable String regionSlug,
            @RequestParam(required = false) String categoria, // slug opzionale della categoria
            @RequestParam(defaultValue = "nome") String orderBy,
            @RequestParam(defaultValue = "asc") String direction) {

        // 1. Recupera la regione o lancia 404
        Regione regione = regioneRepository.findBySlug(regionSlug)
                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Regione non trovata"));

        // 2. Configura l'ordinamento dinamico usando l'import corretto
        Sort.Direction dir = "desc".equalsIgnoreCase(direction) ? Sort.Direction.DESC : Sort.Direction.ASC;
        Sort sort = Sort.by(dir, orderBy);

        List<ProdottoTipico> prodotti;

        // 3. Verifica se l'utente ha inserito anche il filtro categoria nell'URL
        if (categoria != null && !categoria.isBlank()) {
            Categoria cat = categoriaRepository.findBySlug(categoria)
                    .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Categoria non trovata"));
            
            // Usa il metodo combinato del tuo repository
            prodotti = prodottoTipicoRepository.findByRegioneAndCategoria(regione, cat, sort);
        } else {
            // Usa il metodo singolo per regione
            prodotti = prodottoTipicoRepository.findByRegione(regione, sort);
        }

        if (prodotti.isEmpty()) {
            return ResponseEntity.noContent().build();
        }
        return ResponseEntity.ok(prodotti);
    }
}
Usa il codice con cautela.Come testare le rotte appena create:Solo regione: /api/prodotti/regione/piemonte (Ordina per nome ASC di default)Regione + Categoria: /api/prodotti/regione/piemonte?categoria=salumiRegione + Categoria + Ordinamento personalizzato: /api/prodotti/regione/piemonte?categoria=salumi&orderBy=id&direction=descVuoi procedere scrivendo anche l'endpoint del controller per l'ultimo metodo del tuo repository (findByViniSlug), oppure preferisci implementare un sistema di validazione per bloccare le richieste se l'utente inserisce un valore di orderBy non valido?Le risposte dell'AI potrebbero contenere errori. Scopri di piùHai detto: perche uso optional per recuperare il prodotto tipico specifico?L'uso di Optional per recuperare un singolo record (come un ProdottoTipico tramite il suo slug) è una delle migliori pratiche introdotte da Java 8 ed è lo standard consigliato in Spring Boot per tre motivi fondamentali:1. Previene i crash dovuti a NullPointerExceptionSe cerchi un prodotto con un metodo che restituisce direttamente l'oggetto (es. public ProdottoTipico findBySlug(String slug)) e l'utente digita un URL con uno slug inventato o sbagliato (es. /api/prodotti/prodotto-inesistente), il database restituirà null.Se nel tuo codice provi a fare qualsiasi operazione su quel risultato (come chiamare un getter o passarlo a un altro metodo), l'applicazione andrà in crash lanciando un errore di NullPointerException.Con Optional, Spring Data JPA non ti restituisce null, ma un contenitore "vuoto" (Optional.empty()), costringendoti a gestire esplicitamente il caso in cui il dato manchi.2. Permette una gestione degli errori (es. Errore 404) pulita ed eleganteGrazie a Optional, puoi evitare i vecchi e pesanti blocchi di controllo if (prodotto == null). Puoi usare metodi funzionali molto espressivi come .orElseThrow() direttamente nel Service o nel Controller per lanciare un errore HTTP 404 (Not Found) se il prodotto non esiste:java// Se il prodotto esiste lo assegna alla variabile, altrimenti lancia subito il 404
ProdottoTipico prodotto = prodottoTipicoRepository.findBySlug(slug)
        .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Prodotto non trovato"));
Usa il codice con cautela.3. Rende il codice auto-esplicativo (Self-Documenting Code)Chiunque legga il codice del tuo repository capisce immediatamente la natura della query:Se un metodo restituisce una List<ProdottoTipico>, ci si aspetta che possa contenere da 0 a N elementi (la lista vuota indica che non ci sono risultati).Se restituisce un Optional<ProdottoTipico>, la firma del metodo sta dicendo chiaramente: "Questo metodo cercherà un singolo prodotto, ma tieni conto che potrebbe anche non trovarlo".Quando NON si usa Optional?Non si usa mai Optional quando il metodo restituisce una collezione (come List). Se una ricerca per regione non trova prodotti, Spring Data JPA restituisce semplicemente una lista vuota ([]), che è già un oggetto valido e non causa NullPointerException se ciclabile o controllato con .isEmpty().Se vuoi, possiamo vedere come ripulire ulteriormente il controller gestendo tutti questi Optional mancanti tramite un ControllerAdvice centralizzato, così da non dover scrivere .orElseThrow() in ogni singolo endpoint. Desideri approfondire questo aspetto?Le risposte dell'AI potrebbero contenere errori. Scopri di piùHai detto: ora ti mando tutte le entità e mi devi creare un import sql da copiare per popolare il dbPerfetto! Manda pure il codice di tutte le tue entità (le classi Java con le annotazioni @Entity, @Table, @ManyToMany, ecc.).Appena me le avrai inviate, analizzerò le relazioni per capire l'ordine esatto delle tabelle (in modo da evitare errori sui vincoli delle chiavi esterne, i famosi Foreign Key constraints) e ti genererò un file import.sql o data.sql pronto da copiare e incollare.💡 Un piccolo consiglio prima di inviarle:Se hai tabelle particolari o se desideri che inserisca nel database prodotti, vini o regioni di aree specifiche d'Italia (ad esempio, focalizzandoci su una o più regioni in particolare), fammelo sapere così popolerò il database con dati reali e coerenti con la tradizione enogastronomica italiana!Aspetto il codice delle tue